 1	import React, { FC } from 'react';
 2	
 3	import { DataUpload } from '@kubevirt-utils/hooks/useCDIUpload/useCDIUpload';
 4	import {
 5	  UPLOAD_STATUS,
 6	  UPLOAD_STATUS_LABELS,
 7	  uploadStatusToProgressVariant,
 8	} from '@kubevirt-utils/hooks/useCDIUpload/utils';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import {
11	  Button,
12	  ButtonVariant,
13	  FormGroup,
14	  Progress,
15	  ProgressMeasureLocation,
16	  Stack,
17	  StackItem,
18	} from '@patternfly/react-core';
19	
20	export const DiskSourceUploadPVCProgress: FC<{ upload: DataUpload }> = ({ upload }) => {
21	  const { t } = useKubevirtTranslation();
22	  return (
23	    <FormGroup fieldId="upload-progress">
24	      <Stack hasGutter>
25	        <StackItem>
26	          <Progress
27	            measureLocation={ProgressMeasureLocation.inside}
28	            title={UPLOAD_STATUS_LABELS[upload?.uploadStatus]}
29	            value={upload?.progress}
30	            variant={uploadStatusToProgressVariant[upload?.uploadStatus]}
31	          />
32	        </StackItem>
33	        <StackItem>
34	          <Button
35	            isDisabled={
36	              upload?.uploadStatus === UPLOAD_STATUS.CANCELED ||
37	              upload?.uploadStatus === UPLOAD_STATUS.ERROR ||
38	              upload?.uploadStatus === UPLOAD_STATUS.SUCCESS
39	            }
40	            isInline
41	            onClick={() => upload?.cancelUpload()}
42	            variant={ButtonVariant.link}
43	          >
44	            {t('Cancel upload')}
45	          </Button>
46	        </StackItem>
47	      </Stack>
48	    </FormGroup>
49	  );
50	};

